import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    ops = []

    def rev(l):
        a[:l] = a[:l][::-1]
        ops.append(l)

    L = n
    while L > 1:
        big = L  # value that should go to position L-1
        pb = a.index(big)
        ps = a.index(big - 1)

        if pb % 2 == 1:
            rev(pb)
            ps = a.index(big - 1)
            pb = 0
        if pb != 0:
            rev(pb + 1)
            ps = a.index(big - 1)
        # big is now at front
        if ps % 2 == 0:
            rev(ps + 1)
            rev(L)
        else:
            rev(L - 1)
            ps = a.index(big - 1)
            if ps % 2 == 0:
                rev(ps + 1)
            rev(L)
        L -= 2

    if a != sorted(a):
        print(-1)
    else:
        print(len(ops))
        if ops:
            print(*ops)
        else:
            print()

t = int(input())
for _ in range(t):
    solve()

